import requests, json
from urllib3 import disable_warnings
disable_warnings() # To ignore SSL certificate warnings in Python < 3.9 (fetched from https://www.ssl-certificate.org/faq/) 
# Note that this is a simple example and may not work for all cases, you need to handle exceptions appropriately based on your use case  
def fetch_content(url):    
    try:        
        response = requests.get(url)       # Send GET request         
        return json.loads(response.text)[0]['data']  # Return the content of first item in JSON data     
    except Exception as e:  
            print("Error occurred while fetching URL",e )